var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"하악… 하아…!","JPN":"はあっ……はあ……！","ENG":"*Huff...!* *Huff...!*","TWN":"呼呼…呼呼…！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"수가 너무 많잖아! 그 망할 황태자 자식은 어디서 뭘 하고 있는 거야!","JPN":"数が多すぎる！　あのくそ皇太子はどこで何をしてるのよ！","ENG":"There are too many of them! Where is that damned prince?!","TWN":"數量也太多！那該死的皇太子是在幹什麼！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"촌장님. 괜찮으신가요?","JPN":"村長。ご無事ですか？","ENG":"Are you all right, chief?","TWN":"村長，你還好嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"아아, 제를 위한 무대가…","JPN":"ああ、祭祀のための舞台が……","ENG":"Ahh, no... The stage for the rite...","TWN":"呃呃，祭祀的舞台…"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"어떻게. 겨우 이제서야 준비됐는데….","JPN":"そんな。やっと準備できたのに……","ENG":"How. But we only just finished preparing it...","TWN":"怎麼辦，好不容易才準備好…"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"으윽!","JPN":"ううっ！","ENG":"Agh!","TWN":"咳呃！"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"정신 차리시죠. 축제는 목숨만 붙어 있다면 얼마든지 다시 시작할 수 있습니다.","JPN":"しっかりしてください。お祭りなど、生きていればまたいくらでも始めることができます。","ENG":"Get yourself together. The festival can be held again as long as you stay alive.","TWN":"冷靜點，只要活著，慶典隨時可以重辦。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"당장은 살아남는 것만 생각하세요. 당신은 이 마을의 촌장이 아닙니까?","JPN":"今は生き残ることだけを考えてください。あなたは、この村の村長ではありませんか。","ENG":"Focus on surviving. You are the chief of this village, are you not?","TWN":"你現在該想的是如何活下去，你可是這個村子的村長不是嗎？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"……죄송합니다. 이 늙은이가 몹쓸 꼴을 보였군요.","JPN":"……申し訳ありません。この老人がみっともないところをお見せしました。","ENG":"...Forgive me. I was acting foolishly.","TWN":"……對不起，我這老頭真丟人。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"알았으면 마을의 중앙으로 가시죠.","JPN":"わかったなら、村の中央まで行ってください。","ENG":"You've come to your senses. Now, head to the center of the village.","TWN":"快點去村子中央吧。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"살아남은 주민 분들도 그곳에 있을 겁니다.","JPN":"生き残った住民たちもそこにいるはずです。","ENG":"The surviving villagers should be there too.","TWN":"還活著的村民應該都在那裡。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"성녀님께서는 어쩌실 생각입니까?","JPN":"聖女様はどうなさるおつもりですか？","ENG":"What about you, Saintess?","TWN":"聖女打算怎麼做？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"대부분의 짐승은 우두머리를 잃으면 쉽게 와해되기 마련이지요.","JPN":"獣のほとんどはリーダーを失うと簡単に結束が崩れるものです。","ENG":"Most beasts come apart when they lose their leader.","TWN":"俗話說，擒賊先擒王，怪獸的世界亦是如此。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"지원군이 언제 도착할지 모르니, 피해가 확산되기 전에 놈을 치겠습니다.","JPN":"援軍がいつ来るかわからない状況ですから、被害が大きくなる前に奴を討ちます。","ENG":"Since we are unsure of when backup will arrive, I will strike the leader before the damage spreads.","TWN":"不知道援軍什麼時候會到，在損失擴大前我要它解決掉。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"무모합니다! 성녀님 혼자서 그 많은 수를 어떻게…!","JPN":"無茶です！　聖女様お一人で、どうやってあの数の怪獣を……！","ENG":"That's reckless! You cannot handle that many monsters alone...!","TWN":"萬萬不可！聖女，你一個人怎麼對付這麼多……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"제가 아니라면 괴수를 막을 수 있는 사람은 없습니다.","JPN":"私以外に怪獣を止められる者はいません。","ENG":"There is no one else but me that can stop them.","TWN":"現在只有我能夠阻止這些怪獸。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"여기서 도망치는 건 구원자님의 얼굴에 먹칠을 하는 일이겠죠.","JPN":"ここで逃げては救世主様の名を汚すことになります。","ENG":"I would bring disgrace to the Savior if I were to flee in this situation.","TWN":"在這裡逃跑的話，會讓救贖者大人蒙羞吧。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"성녀님이 최선을 다하셨다는 건 모두가 알고 있습니다.","JPN":"聖女様が全力を尽くされたということは、皆わかっています。","ENG":"We all know you did your best, Saintess.","TWN":"大家都知道聖女已經盡力而為，"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"여기서 물러난다고 나무랄 사람이 어디 있겠습니까?","JPN":"ここで引き下がったとしても、誰も責めはしません。","ENG":"Who would ever fault you for stepping back right now?","TWN":"就算撤退也不會有人怪你的。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"…제가 납득하지 못합니다.","JPN":"……私が納得できないのです。","ENG":"...I cannot accept it.","TWN":"……我無法接受。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"예?","JPN":"何ですと？","ENG":"Pardon?","TWN":"什麼？"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"제 걱정은 마시고 촌장님께서는 마을 주민들이 있는 곳으로 가시죠.","JPN":"私は大丈夫ですから、村長は村の住民たちがいるところに向かってください。","ENG":"Don't worry about me, and go to where your people are.","TWN":"別擔心我，村長你快去村民那裡。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIEF_MEMORIAL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"저는…….","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"HOLY_MEMORIAL_NPC_NULL","text":{"KOREA":"구원자님의 도움이 되어야 해요.","JPN":"救世主様のお役に立たなければ。","ENG":"I must be of help to the Savior.","TWN":"我要成為救贖者大人的幫助。"},"stage":{"bg":"CAMP_NIGHT","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HOLY_MEMORIAL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};